sub_queries.sql:
SELECT District, Senator AS Name, Party, Term_Limited FROM T40
UNION ALL
SELECT District, Representative AS Name, Party, Term_Limited FROM T41;

SELECT District, Senator, First_elected, Term_Limited FROM T40
UNION ALL
SELECT District, Representative, First_Elected AS First_elected, Term_Limited FROM T41;

SELECT Province, COUNT(*) AS frequency
FROM T14
GROUP BY Province;

SELECT Province, Election_date 
FROM T14 
GROUP BY Province, Election_date;

SELECT Score, COUNT(*) AS Score_count 
FROM T64 
GROUP BY Score;

SELECT MIN(Election_date) AS Start_Date, MAX(Election_date) AS End_Date
FROM T14
WHERE Member IN ('William Moorhouse', 'Thomas Bartley', 'Loughlin O''Brien');
